import{_ as e,c as a,o as i,d as t}from"./app.05a75977.js";const g=JSON.parse('{"title":"Chapter 3: The Complete ML Pipeline","description":"","frontmatter":{},"headers":[{"level":2,"title":"3.1 What is an ML Pipeline?","slug":"_3-1-what-is-an-ml-pipeline","link":"#_3-1-what-is-an-ml-pipeline","children":[]},{"level":2,"title":"3.2 Data Collection","slug":"_3-2-data-collection","link":"#_3-2-data-collection","children":[]},{"level":2,"title":"3.3 Data Preprocessing","slug":"_3-3-data-preprocessing","link":"#_3-3-data-preprocessing","children":[]},{"level":2,"title":"3.4 Training","slug":"_3-4-training","link":"#_3-4-training","children":[]},{"level":2,"title":"3.5 Evaluation","slug":"_3-5-evaluation","link":"#_3-5-evaluation","children":[]},{"level":2,"title":"3.6 Deployment (Overview)","slug":"_3-6-deployment-overview","link":"#_3-6-deployment-overview","children":[]},{"level":2,"title":"3.7 A Clear Flow","slug":"_3-7-a-clear-flow","link":"#_3-7-a-clear-flow","children":[]},{"level":2,"title":"3.8 Why This Pipeline Matters","slug":"_3-8-why-this-pipeline-matters","link":"#_3-8-why-this-pipeline-matters","children":[]},{"level":2,"title":"3.9 What Comes Next","slug":"_3-9-what-comes-next","link":"#_3-9-what-comes-next","children":[]},{"level":2,"title":"Chapter Summary","slug":"chapter-summary","link":"#chapter-summary","children":[]}],"relativePath":"ml-foundation/en/part1/the-complete-ml-pipeline.md"}'),l={name:"ml-foundation/en/part1/the-complete-ml-pipeline.md"},n=t('<h1 id="chapter-3-the-complete-ml-pipeline" tabindex="-1">Chapter 3: The Complete ML Pipeline <a class="header-anchor" href="#chapter-3-the-complete-ml-pipeline" aria-hidden="true">#</a></h1><hr><h2 id="_3-1-what-is-an-ml-pipeline" tabindex="-1">3.1 What is an ML Pipeline? <a class="header-anchor" href="#_3-1-what-is-an-ml-pipeline" aria-hidden="true">#</a></h2><ul><li>A step-by-step process to build an ML system</li><li>Converts raw data \u2192 useful predictions</li></ul><blockquote><p>It defines how data flows from start to end.</p></blockquote><p>An ML pipeline is the complete journey of a Machine Learning system. It starts with collecting raw data and ends with making predictions in real-world applications. Each step in this pipeline is important, and skipping or poorly handling any step can lead to incorrect results. Understanding this pipeline helps you think like an ML engineer, not just a coder.</p><hr><h2 id="_3-2-data-collection" tabindex="-1">3.2 Data Collection <a class="header-anchor" href="#_3-2-data-collection" aria-hidden="true">#</a></h2><ul><li>Gathering raw data</li><li>Source of learning for the model</li></ul><p>Examples:</p><ul><li>CSV files</li><li>Databases</li><li>APIs</li><li>Sensors</li></ul><p>Data collection is the first and most important step. The model can only learn from the data it is given. If the data is poor, incomplete, or biased, the model will also produce poor results. In real-world systems, a lot of effort goes into collecting high-quality and relevant data.</p><hr><h2 id="_3-3-data-preprocessing" tabindex="-1">3.3 Data Preprocessing <a class="header-anchor" href="#_3-3-data-preprocessing" aria-hidden="true">#</a></h2><ul><li>Cleaning and preparing data</li><li>Making data usable for models</li></ul><p>Includes:</p><ul><li>Handling missing values</li><li>Removing noise</li><li>Encoding categorical data</li><li>Feature scaling</li></ul><p>Raw data is usually messy and cannot be used directly. Data preprocessing transforms this raw data into a clean and structured format. For example, missing values may need to be filled, text may need to be converted into numbers, and features may need to be scaled. This step ensures that the model receives meaningful and consistent input.</p><hr><h2 id="_3-4-training" tabindex="-1">3.4 Training <a class="header-anchor" href="#_3-4-training" aria-hidden="true">#</a></h2><ul><li>Model learns patterns from data</li><li>Uses training dataset</li></ul><p>Training is the phase where the model actually learns. It looks at the input data and tries to find patterns that connect inputs to outputs. During training, the model adjusts its internal parameters to reduce errors. This process is repeated multiple times until the model becomes accurate enough.</p><hr><h2 id="_3-5-evaluation" tabindex="-1">3.5 Evaluation <a class="header-anchor" href="#_3-5-evaluation" aria-hidden="true">#</a></h2><ul><li>Testing model performance</li><li>Uses separate test data</li></ul><p>Metrics:</p><ul><li>Accuracy</li><li>Precision</li><li>Recall</li></ul><p>Evaluation helps us understand how well the model is performing. Instead of testing on the same data used for training, we use separate data to check if the model can generalize to new inputs. This step is important to avoid overfitting and ensure the model works in real-world scenarios.</p><hr><h2 id="_3-6-deployment-overview" tabindex="-1">3.6 Deployment (Overview) <a class="header-anchor" href="#_3-6-deployment-overview" aria-hidden="true">#</a></h2><ul><li>Using model in real-world applications</li><li>Making predictions on new data</li></ul><p>Examples:</p><ul><li>Web applications</li><li>Mobile apps</li><li>APIs</li></ul><p>Deployment is the final step where the trained model is put into production. This means the model is now used by real users or systems to make predictions. For example, a spam detection model may be deployed inside an email service, or a recommendation model may be used in an e-commerce app. Deployment turns a model from an experiment into a usable product.</p><hr><h2 id="_3-7-a-clear-flow" tabindex="-1">3.7 A Clear Flow <a class="header-anchor" href="#_3-7-a-clear-flow" aria-hidden="true">#</a></h2><ul><li>Data Collection \u2192 gather data</li><li>Data Preprocessing \u2192 clean data</li><li>Training \u2192 learn patterns</li><li>Evaluation \u2192 test performance</li><li>Deployment \u2192 use in real world</li></ul><p>This flow represents the lifecycle of most Machine Learning systems.</p><hr><h2 id="_3-8-why-this-pipeline-matters" tabindex="-1">3.8 Why This Pipeline Matters <a class="header-anchor" href="#_3-8-why-this-pipeline-matters" aria-hidden="true">#</a></h2><ul><li>Ensures structured development</li><li>Reduces errors</li><li>Improves model performance</li></ul><p>Understanding the ML pipeline helps you approach problems systematically. Instead of randomly trying models, you follow a clear process, which leads to better and more reliable results.</p><hr><h2 id="_3-9-what-comes-next" tabindex="-1">3.9 What Comes Next <a class="header-anchor" href="#_3-9-what-comes-next" aria-hidden="true">#</a></h2><p>Now that you understand how an ML system works end-to-end, the next step is to go deeper into the most critical part:</p><blockquote><p>Understanding Data \u2014 the foundation of all Machine Learning systems</p></blockquote><hr><h2 id="chapter-summary" tabindex="-1">Chapter Summary <a class="header-anchor" href="#chapter-summary" aria-hidden="true">#</a></h2><ul><li>ML pipeline is a step-by-step process</li><li>It starts with data and ends with deployment</li><li>Each step plays a critical role</li><li>Good data and proper evaluation are key to success</li></ul><hr>',50),r=[n];function s(o,d,p,h,c,m){return i(),a("div",null,r)}const f=e(l,[["render",s]]);export{g as __pageData,f as default};
